const raw = $input.first().json;
const body = raw.body || raw;

// Accept both camelCase (from Vercel /api/analyse) and snake_case (legacy)
const businessType  = body.businessType  || body.business_type  || '';
const monthlyRent   = Number(body.monthlyRent   || body.monthly_rent   || 0);
const setupBudget   = Number(body.setupBudget   || body.setup_cost     || body.setupCost || 0);
const avgTicketSize = Number(body.avgTicketSize || body.avg_ticket_size || 0);
const rawUserId     = body.userId || body.user_id || null;
const userId        = (rawUserId && rawUserId !== 'anonymous') ? rawUserId : null;
const reportId      = body.reportId || body.report_id || ('RPT-' + Date.now());
const address       = body.address  || '';

if (!businessType) throw new Error('Missing required field: businessType');
if (!address)      throw new Error('Missing required field: address');
if (!monthlyRent)  throw new Error('Missing required field: monthlyRent');

// CRITICAL FIX v6: use body.area (specific suburb) NOT just city
// Vercel /api/analyse parses '421 Brunswick St, Fitzroy VIC 3065' → area='Fitzroy', city='Melbourne'
// v5 bug: area was set to city ('Melbourne'), causing A1/A2 to search wrong suburb
const suburb = body.area || body.suburb || body.locality || '';

let city = body.city || '';
if (!city && address) {
  const parts = address.split(',').map(p => p.trim()).filter(Boolean);
  if (parts.length >= 2) {
    city = (parts[parts.length - 2] || '').replace(/\s+\d{4,6}.*$/, '').trim();
  }
}

const state    = body.state    || '';
const postcode = body.postcode || '';

let country = body.country || 'Australia';
if (address) {
  if (/\bUSA?\b/i.test(address) || /\bUnited States\b/i.test(address) ||
      /,\s*[A-Z]{2}\s+\d{5}/.test(address)) {
    country = 'USA';
  } else if (/\bUK\b/i.test(address) || /\bUnited Kingdom\b/i.test(address)) {
    country = 'UK';
  } else if (/\bAustralia\b/i.test(address) || /\bVIC\b/.test(address) ||
             /\bNSW\b/.test(address) || /\bQLD\b/.test(address) ||
             /\bWA\b/.test(address)  || /\bSA\b/.test(address)) {
    country = 'Australia';
  }
}
const currency = country === 'USA' ? 'USD' : country === 'UK' ? 'GBP' : (body.currency || 'AUD');

return [{ json: {
  report_id:       reportId,
  submission_id:   body.submissionId || reportId,
  business_type:   businessType,
  industry_category: businessType,
  // v6 FIX: area = actual suburb (e.g. 'Wembley'), not metro city (e.g. 'Perth')
  area:            suburb || city,
  locality:        suburb || city,
  city:            city,
  state:           state,
  postcode:        postcode,
  address:         address,
  country:         country,
  currency:        currency,
  email:           body.email      || '',
  mode:            (body.mode === 'light') ? 'light' : 'full',
  lat:             body.lat        || '',
  lng:             body.lng        || '',
  monthly_rent:    monthlyRent,
  setup_cost:      setupBudget,
  avg_ticket_size: avgTicketSize,
  monthly_revenue: Number(body.monthly_revenue || body.monthlyRevenue || 0),
  staff_count:     Number(body.staff_count     || body.staffCount     || 1),
  user_id:         userId,
  _start_time:     Date.now()
}}];

const resp = $input.first().json;
const prev = $('Parse Inputs').first().json;
const isHttpErr = typeof resp.statusCode === 'number' && resp.statusCode >= 400;
const isNetErr  = !!(resp.code && ['ECONNREFUSED','ETIMEDOUT','ENOTFOUND','ECONNRESET'].includes(resp.code));
const isErrItem = !!(resp.error !== undefined && resp.message !== undefined && resp.statusCode !== undefined);
const isFailed  = isHttpErr || isNetErr || isErrItem;
return [{ json: { ...prev, a1_status: isFailed ? 'failed' : 'ok', a1_failed: isFailed, a1_error: isFailed ? (resp.message || JSON.stringify(resp.error || resp).slice(0,300)) : null, a1_data: isFailed ? null : resp }}];

