// v8: Package Raw Data — ZERO computation here.
// computeEngine() in /api/compute is the ONLY source of financial truth.
// This node just assembles the 6 agent outputs for Supabase + /api/compute.

const d = $input.first().json;

const a1 = d.a1_data || {};
const a2 = d.a2_data || {};
const a3 = d.a3_data || {};
const a4 = d.a4_data || {};
const a5 = d.a5_data || {};
const a6 = d.a6_data || {};

return [{ json: {
  report_id:  d.report_id,
  user_id:    (d.user_id && d.user_id !== 'anonymous') ? d.user_id : null,

  // Keyed for /api/compute
  agentOutputs: { a1, a2, a3, a4, a5, a6 },

  // Flat structure for backward-compat reads (V1 legacy path in dashboard)
  result_data: {
    competitors: a1,
    rentData:    a2,
    market:      a3,
    financials:  a4,
    revenue:     a5,
    demographics: a6,
    agent_statuses: {
      a1: d.a1_status, a2: d.a2_status, a3: d.a3_status,
      a4: d.a4_status, a5: d.a5_status, a6: d.a6_status
    },
    errors: {
      a1: d.a1_error, a2: d.a2_error, a3: d.a3_error,
      a4: d.a4_error, a5: d.a5_error, a6: d.a6_error
    }
  }
}}];

const pkg         = $('Package Raw Data').first().json;
const computeResp = $input.first().json;

const isHttpErr  = typeof computeResp.statusCode === 'number' && computeResp.statusCode >= 400;
const computeOk  = computeResp.success === true && !isHttpErr;
const errDetail  = computeOk ? null : (computeResp.error || JSON.stringify(computeResp).slice(0, 300));

if (!computeOk) {
  console.error('[v6] /api/compute failed for', pkg.report_id, ':', errDetail);
}

return [{ json: {
  success:       computeOk,
  report_id:     pkg.report_id,
  compute_ok:    computeOk,
  compute_error: errDetail,
  verdict:       computeOk ? computeResp.verdict    : null,
  net_profit:    computeOk ? computeResp.netProfit  : null,
  engine_ver:    computeOk ? computeResp.engineVersion : null
}}];
